import{_ as e,o,c as r,a2 as d}from"./chunks/framework.CY0RMtsF.js";const a="/mug-typography-docs/image/inspector_copy_paste.webp",s="/mug-typography-docs/image/inspector_overlay_settings.webp",f=JSON.parse('{"title":"コピー・ペースト / オーバーレイ設定","description":"","frontmatter":{"title":"コピー・ペースト / オーバーレイ設定"},"headers":[],"relativePath":"reference/reference-utility-settings.md","filePath":"reference/reference-utility-settings.md"}'),i={name:"reference/reference-utility-settings.md"};function n(l,t,c,p,g,h){return o(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="✨-page-copy-paste" tabindex="-1">✨ Page: Copy / Paste <a class="header-anchor" href="#✨-page-copy-paste" aria-label="Permalink to &quot;✨ Page: Copy / Paste&quot;">​</a></h1><p>選択中の文字・パーツが持つパラメーター（位置・スケール・色など）を別の文字・パーツへコピー＆ペーストするページです。1か所で調整した見た目を、他の文字へすばやく横展開したいときに使います。</p><p><img src="'+a+'" alt="Copy / Paste ページ"></p><h2 id="基本的な使い方" tabindex="-1">基本的な使い方 <a class="header-anchor" href="#基本的な使い方" aria-label="Permalink to &quot;基本的な使い方&quot;">​</a></h2><ol><li>プレビュー画面で、コピー<strong>元</strong>となる文字またはパーツを 1 つ選択します。</li><li><strong>Copy Selection</strong> ボタン（または <code>Alt+Shift+Y</code>）を押します。<strong>Copied Source</strong> 欄に、現在コピー元として保持している対象が表示されます。</li><li>このページの下部にあるチェックボックスで、<strong>貼り付けたいパラメーターだけ</strong>を ON にします。</li><li>プレビュー画面で、貼り付け<strong>先</strong>となる文字・パーツを選択します（複数選択可）。</li><li><strong>Paste to Selection</strong> ボタン（または <code>Alt+Shift+U</code>）を押すと、チェックした項目だけが貼り付け先に適用されます。</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>コピー元・貼り付け先は、文字どうし／パーツどうしだけでなく、<strong>文字とパーツを混在</strong>させて貼り付けることもできます。その際、一方にしか存在しないパラメーター（例: 文字専用の Margin After をパーツへ貼り付け）は自動的にスキップされます。</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>コピーされるのは、<strong>Copy Selection を押したフレーム時点の値</strong>です。そのため、同じ文字・パーツを選んだまま別のフレームでペーストすれば、<strong>自分自身の「別の時間の設定」をコピー＆ペースト</strong>できます。たとえば、あるフレームの状態を後のフレームへ複製してアニメーションを止める、といった使い方が可能です。</p></div><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Copy Selection</strong> (<code>Alt+Shift+Y</code>)</td><td>現在選択中の文字・パーツのパラメーター値を、<strong>そのフレーム時点の値のまま</strong>コピー元として記憶します。</td><td>—</td></tr><tr><td><strong>Paste to Selection</strong> (<code>Alt+Shift+U</code>)</td><td>コピー元の、チェックされたパラメーターを現在の選択へ書き込みます。書き込み先は、ペーストした時点のフレームです。</td><td>—</td></tr><tr><td><strong>Copied Source</strong></td><td>現在コピー元として保持している対象と、コピーしたフレーム番号（例: <code>Char 3 (12f)</code>）を表示する欄です（表示専用・編集不可）。</td><td>(none)</td></tr></tbody></table><h3 id="貼り付け対象の選択-チェックボックス" tabindex="-1">貼り付け対象の選択（チェックボックス） <a class="header-anchor" href="#貼り付け対象の選択-チェックボックス" aria-label="Permalink to &quot;貼り付け対象の選択（チェックボックス）&quot;">​</a></h3><p>貼り付ける項目は、以下のチェックボックスで個別に ON/OFF します。<code>(char only)</code> と付いた項目は文字専用で、パーツへの貼り付け時には無視されます。</p><table tabindex="0"><thead><tr><th>区分</th><th>項目</th></tr></thead><tbody><tr><td>変形（既定 OFF）</td><td>Offset X / Offset Y / Pivot X / Pivot Y / Scale / Rotation / Stretch X / Stretch Y</td></tr><tr><td>カラー（既定 ON）</td><td>Use Individual Color / Color</td></tr><tr><td>文字専用（既定 ON）</td><td>Margin After / Use Stroke / Stroke Width / Stroke Gap / Stroke Color / Use Shadow Color / Shadow Color</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Offset・Pivot・Stretch は X と Y を個別にチェックできるため、例えば「X 方向の位置だけを揃える」といった貼り付けも可能です。</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>ショートカット <code>Alt+Shift+Y</code> / <code>Alt+Shift+U</code> のキー部分は <code>preferences.json</code> でカスタマイズ可能です（<code>Alt+Shift</code> などの修飾キーは変更できません）。</p></div><hr><p><a id="page-overlay-settings"></a></p><h1 id="page-overlay-settings" tabindex="-1">Page: Overlay Settings <a class="header-anchor" href="#page-overlay-settings" aria-label="Permalink to &quot;Page: Overlay Settings&quot;">​</a></h1><p>プレビュー画面に表示されるハンドルやアウトラインの見た目を変更するページです。</p><p><img src="'+s+'" alt="Overlay Settings"></p><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Unselected Color</strong></td><td>選択されていない文字・パーツの境界線の色</td></tr><tr><td><strong>Selected Color</strong></td><td>選択中の文字・パーツの境界線の色</td></tr><tr><td><strong>Previewing Color</strong></td><td>マーキー選択中・マージンプレビュー時の色</td></tr><tr><td><strong>Handle Color</strong></td><td>移動・回転・スケール操作ハンドルの色</td></tr><tr><td>✨ <strong>Outline Enabled</strong></td><td>境界線表示の ON/OFF を切り替えます。<br>プレビュー画面にフォーカスがある状態で <code>Alt+;</code>（セミコロン / macOS: <code>Option+;</code>）を押すことでも素早くトグルできます。</td></tr><tr><td><strong>Outline Color</strong></td><td>境界線の色（Outline Enabled が ON のとき有効）</td></tr></tbody></table><hr><p><a id="appendix-ja"></a></p>',21)])])}const u=e(i,[["render",n]]);export{f as __pageData,u as default};
